        if (greenPlanet != null) {
            if (AdofaiTweaks.ReleaseNumber >= 128) {
                LoadPlanetColorWithRenderer(greenPlanet);
            } else {
                LoadPlanetColor(greenPlanet);
            }
        }
    }
